import{c as n,Z as e,Q as p,j as t,o as l,m as i}from"./chunks/framework.qjzPVSkb.js";const k=JSON.parse('{"title":"用 Claude 分析文档","description":"上传 PDF 论文、合同、技术文档，让 Claude 快速提取核心信息并生成结构化分析","frontmatter":{"title":"用 Claude 分析文档","description":"上传 PDF 论文、合同、技术文档，让 Claude 快速提取核心信息并生成结构化分析","difficulty":"beginner"},"headers":[],"relativePath":"practices/claude-analysis.md","filePath":"practices/claude-analysis.md"}'),d={name:"practices/claude-analysis.md"};function o(c,a,r,h,u,b){const s=e("DifficultyBadge");return p(),t("div",null,[l(s,{level:"beginner"}),a[0]||(a[0]=i(`<h1 id="用-claude-分析文档" tabindex="-1">用 Claude 分析文档 <a class="header-anchor" href="#用-claude-分析文档" aria-label="Permalink to &quot;用 Claude 分析文档&quot;">​</a></h1><p>Claude 的 200K 上下文窗口是分析长文档的利器。本篇教你如何高效利用它来阅读论文、分析合同、处理技术文档。</p><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><ul><li>注册 <a href="https://claude.ai" target="_blank" rel="noreferrer">Claude</a> 账号（免费版即可，但 Pro 版体验更好）</li><li>准备一份要分析的文档（PDF、Word、TXT 等格式都支持）</li></ul><hr><h2 id="第-1-步-上传文档" tabindex="-1">第 1 步：上传文档 <a class="header-anchor" href="#第-1-步-上传文档" aria-label="Permalink to &quot;第 1 步：上传文档&quot;">​</a></h2><p>打开 Claude 网页版，点击输入框旁的 📎 附件图标，选择你要分析的文档。</p><p>Claude 会自动&quot;阅读&quot;整个文档。200K tokens 的上下文意味着它可以一次性处理：</p><ul><li>约 15 万英文单词</li><li>约 200 页 PDF</li><li>整本中等篇幅的书</li></ul><h3 id="支持的文件格式" tabindex="-1">支持的文件格式 <a class="header-anchor" href="#支持的文件格式" aria-label="Permalink to &quot;支持的文件格式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>格式</th><th>支持</th><th>说明</th></tr></thead><tbody><tr><td>PDF</td><td>✅</td><td>扫描版 PDF 也能处理（OCR）</td></tr><tr><td>Word (.docx)</td><td>✅</td><td>保留格式</td></tr><tr><td>Excel (.xlsx)</td><td>✅</td><td>可以分析表格数据</td></tr><tr><td>TXT</td><td>✅</td><td>纯文本</td></tr><tr><td>图片</td><td>✅</td><td>支持图像理解</td></tr><tr><td>PPT</td><td>✅</td><td>可以分析演示文稿</td></tr></tbody></table><hr><h2 id="第-2-步-提出分析要求" tabindex="-1">第 2 步：提出分析要求 <a class="header-anchor" href="#第-2-步-提出分析要求" aria-label="Permalink to &quot;第 2 步：提出分析要求&quot;">​</a></h2><p>文档上传后，就可以开始提问。根据文档类型，提问方式不同。</p><h3 id="场景-1-分析学术论文" tabindex="-1">场景 1：分析学术论文 <a class="header-anchor" href="#场景-1-分析学术论文" aria-label="Permalink to &quot;场景 1：分析学术论文&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：请分析这篇论文，回答以下问题：</span></span>
<span class="line"><span>1. 论文的核心贡献是什么？</span></span>
<span class="line"><span>2. 作者提出了什么新方法？和现有方法有什么区别？</span></span>
<span class="line"><span>3. 实验结论是什么？有哪些关键数据？</span></span>
<span class="line"><span>4. 有什么局限性或未来工作方向？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>用中文回答，结构要清晰。</span></span></code></pre></div><p>Claude 会给出结构化的分析：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 论文核心贡献</span></span>
<span class="line"><span>本文提出了 XXX 方法，解决了 XXX 问题...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 方法论</span></span>
<span class="line"><span>创新点在于：</span></span>
<span class="line"><span>1. ...</span></span>
<span class="line"><span>2. ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 实验结论</span></span>
<span class="line"><span>在 XXX 数据集上，该方法比 baseline 提升了 15%...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 局限性</span></span>
<span class="line"><span>作者指出...</span></span></code></pre></div><h3 id="场景-2-审查合同" tabindex="-1">场景 2：审查合同 <a class="header-anchor" href="#场景-2-审查合同" aria-label="Permalink to &quot;场景 2：审查合同&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：请审查这份合同，找出以下风险点：</span></span>
<span class="line"><span>1. 违约责任条款是否对某一方不公平？</span></span>
<span class="line"><span>2. 知识产权归属有没有隐患？</span></span>
<span class="line"><span>3. 解除条款的条件是否合理？</span></span>
<span class="line"><span>4. 是否有隐藏的自动续约条款？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请逐条列出风险，用&quot;⚠️ 高风险 / ⚡ 中风险 / ℹ️ 低风险&quot;标注等级。</span></span></code></pre></div><h3 id="场景-3-分析技术文档" tabindex="-1">场景 3：分析技术文档 <a class="header-anchor" href="#场景-3-分析技术文档" aria-label="Permalink to &quot;场景 3：分析技术文档&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：这是我们的项目技术文档。请帮我：</span></span>
<span class="line"><span>1. 总结系统架构</span></span>
<span class="line"><span>2. 画出核心流程（用文字描述即可）</span></span>
<span class="line"><span>3. 找出文档中矛盾或不清楚的地方</span></span>
<span class="line"><span>4. 列出所有 API 接口及其功能</span></span></code></pre></div><h3 id="场景-4-对比多个文档" tabindex="-1">场景 4：对比多个文档 <a class="header-anchor" href="#场景-4-对比多个文档" aria-label="Permalink to &quot;场景 4：对比多个文档&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：我上传了两份简历。请用表格对比两人的背景：</span></span>
<span class="line"><span>- 教育背景</span></span>
<span class="line"><span>- 工作经历</span></span>
<span class="line"><span>- 技能匹配度</span></span>
<span class="line"><span>- 优缺点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最后给出你的推荐（假设招聘岗位是前端开发工程师）。</span></span></code></pre></div><hr><h2 id="第-3-步-利用长上下文深入分析" tabindex="-1">第 3 步：利用长上下文深入分析 <a class="header-anchor" href="#第-3-步-利用长上下文深入分析" aria-label="Permalink to &quot;第 3 步：利用长上下文深入分析&quot;">​</a></h2><p>Claude 的强项是一次性处理大量信息。充分利用这一点：</p><h3 id="逐章分析" tabindex="-1">逐章分析 <a class="header-anchor" href="#逐章分析" aria-label="Permalink to &quot;逐章分析&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：这本书一共 12 章，我已经全部上传。请：</span></span>
<span class="line"><span>1. 给出每章的一句话摘要</span></span>
<span class="line"><span>2. 指出各章之间的逻辑关系</span></span>
<span class="line"><span>3. 提炼全书的 3 个核心观点</span></span></code></pre></div><h3 id="跨文档关联" tabindex="-1">跨文档关联 <a class="header-anchor" href="#跨文档关联" aria-label="Permalink to &quot;跨文档关联&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：我上传了同一项目的需求文档、技术方案和测试报告。</span></span>
<span class="line"><span>请分析：技术方案是否完整覆盖了需求文档中的所有需求点？</span></span>
<span class="line"><span>哪些需求没有对应的技术方案？</span></span></code></pre></div><h3 id="追问细节" tabindex="-1">追问细节 <a class="header-anchor" href="#追问细节" aria-label="Permalink to &quot;追问细节&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：你刚才提到的 XXX 方法，论文里有没有解释为什么选这个参数值？</span></span></code></pre></div><p>Claude 会回到文档中查找细节——全程记住对话历史。</p><hr><h2 id="第-4-步-获得结构化输出" tabindex="-1">第 4 步：获得结构化输出 <a class="header-anchor" href="#第-4-步-获得结构化输出" aria-label="Permalink to &quot;第 4 步：获得结构化输出&quot;">​</a></h2><p>对于需要复用的分析结果，可以让 Claude 以特定格式输出。</p><h3 id="要求-markdown-表格" tabindex="-1">要求 Markdown 表格 <a class="header-anchor" href="#要求-markdown-表格" aria-label="Permalink to &quot;要求 Markdown 表格&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：请把这篇文章中提到的所有技术方案整理成表格：</span></span>
<span class="line"><span>| 方案名称 | 适用场景 | 优点 | 缺点 | 复杂度 |</span></span></code></pre></div><h3 id="要求-json" tabindex="-1">要求 JSON <a class="header-anchor" href="#要求-json" aria-label="Permalink to &quot;要求 JSON&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你：请把合同中的关键条款提取为 JSON 格式：</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;parties&quot;: [&quot;甲方&quot;, &quot;乙方&quot;],</span></span>
<span class="line"><span>  &quot;effective_date&quot;: &quot;2026-01-01&quot;,</span></span>
<span class="line"><span>  &quot;payment_terms&quot;: { ... },</span></span>
<span class="line"><span>  &quot;termination&quot;: { ... }</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="实用-prompt-模板" tabindex="-1">实用 Prompt 模板 <a class="header-anchor" href="#实用-prompt-模板" aria-label="Permalink to &quot;实用 Prompt 模板&quot;">​</a></h2><h3 id="论文精读" tabindex="-1">论文精读 <a class="header-anchor" href="#论文精读" aria-label="Permalink to &quot;论文精读&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请作为我的研究助手，精读这篇论文：</span></span>
<span class="line"><span>1. 用一段话概括核心思想（限制 200 字）</span></span>
<span class="line"><span>2. 列出 3 个最重要的创新点</span></span>
<span class="line"><span>3. 解释 Figure 3 和 Figure 5 说明了什么</span></span>
<span class="line"><span>4. 这个方法在我描述的以下场景中能用吗：[描述你的场景]</span></span>
<span class="line"><span>5. 推荐 3 篇相关论文（不要求真的找到，给出方向即可）</span></span></code></pre></div><h3 id="会议纪要" tabindex="-1">会议纪要 <a class="header-anchor" href="#会议纪要" aria-label="Permalink to &quot;会议纪要&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请把这 2 小时的会议录音转写内容整理成纪要：</span></span>
<span class="line"><span>1. 结论性决定（标出责任人）</span></span>
<span class="line"><span>2. 待办事项（TODO list）</span></span>
<span class="line"><span>3. 分歧点（未达成共识的事项）</span></span>
<span class="line"><span>4. 下次会议建议议程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>格式：Markdown，每一项前面用 checkbox。</span></span></code></pre></div><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th></tr></thead><tbody><tr><td>1</td><td>上传文档（PDF / Word / TXT 等）</td></tr><tr><td>2</td><td>提出结构化分析要求</td></tr><tr><td>3</td><td>利用长上下文深入提问</td></tr><tr><td>4</td><td>获得结构化输出（Markdown / JSON）</td></tr></tbody></table><p>Claude 的 200K 上下文窗口让它成为长文档分析的首选工具。搭配清晰的 Prompt，你可以快速从海量信息中提炼出真正有价值的内容。</p><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/tools/claude.html">Claude 工具详解</a></li><li><a href="/ai-knowledge/prompts/principles.html">清晰的 Prompt 怎么写</a></li><li><a href="/ai-knowledge/practices/rag-knowledge-base.html">搭建 RAG 知识库</a> —— 比手动上传更强大的文档分析方案</li></ul>`,53))])}const m=n(d,[["render",o]]);export{k as __pageData,m as default};
